def image_convert(data, context):
    import subprocess
    import os
    from google.cloud import storage

    client = storage.Client()
    bucket_name = data['bucket']
    file_name = data['name']
    metadata = data.get('metadata', {})
    conversion_options = metadata.get('conversion_options', '')

    if not conversion_options:
        print("No conversion options provided.")
        return

    bucket = client.get_bucket(bucket_name)
    blob = bucket.blob(file_name)
    temp_file_path = f"/tmp/{file_name}"

    blob.download_to_filename(temp_file_path)

    output_file_name = f"converted-{file_name}"
    output_file_path = f"/tmp/{output_file_name}"

    try:
        subprocess.call(['convert', temp_file_path] + conversion_options.split() + [output_file_path])
        output_blob = bucket.blob(output_file_name)
        output_blob.upload_from_filename(output_file_path)
    finally:
        if os.path.exists(temp_file_path):
            os.remove(temp_file_path)
        if os.path.exists(output_file_path):
            os.remove(output_file_path)